-- Food Delivery Analytics Schema
CREATE TABLE customers (Customer_ID VARCHAR(20) PRIMARY KEY, Age INT, Gender VARCHAR(20), City VARCHAR(50), Signup_Date DATE, Loyalty_Status VARCHAR(20), Total_Orders INT, Average_Spend DECIMAL(10,2), Customer_Lifetime_Value DECIMAL(12,2));
CREATE TABLE restaurants (Restaurant_ID VARCHAR(20) PRIMARY KEY, Restaurant_Name VARCHAR(100), Cuisine VARCHAR(50), Average_Preparation_Time DECIMAL(5,2), Rating DECIMAL(3,1), Total_Orders INT, Revenue DECIMAL(12,2));
CREATE TABLE delivery_partners (Partner_ID VARCHAR(20) PRIMARY KEY, Vehicle_Type VARCHAR(30), Ratings DECIMAL(3,1), Completed_Orders INT, Average_Delivery_Time DECIMAL(5,2));
CREATE TABLE orders (Order_ID VARCHAR(20) PRIMARY KEY, Customer_ID VARCHAR(20), Restaurant_ID VARCHAR(20), Delivery_Partner_ID VARCHAR(20), Order_Time TIMESTAMP, Delivery_Time TIMESTAMP, Delivery_Duration DECIMAL(6,2), Order_Value DECIMAL(10,2), Discount DECIMAL(10,2), Final_Price DECIMAL(10,2), Profit DECIMAL(10,2), Payment_Method VARCHAR(30), Order_Status VARCHAR(30), Customer_Rating DECIMAL(3,1), Delivery_City VARCHAR(50), Distance_km DECIMAL(6,2), Weather VARCHAR(30), Traffic_Level VARCHAR(20), Delivery_Delay DECIMAL(6,2), Peak_Hour_Indicator INT, Weekend_Indicator INT, Delivery_Efficiency_Score DECIMAL(5,2), Profit_Margin DECIMAL(6,3), Revenue_Bucket VARCHAR(20), FOREIGN KEY(Customer_ID) REFERENCES customers(Customer_ID), FOREIGN KEY(Restaurant_ID) REFERENCES restaurants(Restaurant_ID));
